# Generated by openai (gpt-5.4)
# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import io
import re
import time
import json
import uuid
import hashlib
import logging
import tempfile
from typing import Optional, Tuple
from urllib.parse import urlparse

import boto3
from botocore.exceptions import ClientError
from flask import Flask, request, jsonify
from PIL import Image

from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.common.exceptions import WebDriverException, TimeoutException


logging.basicConfig(
    level=os.getenv("LOG_LEVEL", "INFO"),
    format="%(asctime)s %(levelname)s %(name)s %(message)s",
)
logger = logging.getLogger("screenshot-service")

app = Flask(__name__)

AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
PUBLIC_BASE_URL = os.getenv("PUBLIC_BASE_URL", "")
CHROME_BINARY = os.getenv("CHROME_BINARY", "/usr/bin/google-chrome")
CHROMEDRIVER_PATH = os.getenv("CHROMEDRIVER_PATH", "/usr/bin/chromedriver")
PAGELOAD_TIMEOUT = int(os.getenv("PAGELOAD_TIMEOUT", "25"))
RENDER_WAIT_SECONDS = float(os.getenv("RENDER_WAIT_SECONDS", "2.5"))
VIEWPORT_WIDTH = int(os.getenv("VIEWPORT_WIDTH", "1280"))
VIEWPORT_HEIGHT = int(os.getenv("VIEWPORT_HEIGHT", "720"))
THUMB_WIDTH = int(os.getenv("THUMB_WIDTH", "600"))
THUMB_HEIGHT = int(os.getenv("THUMB_HEIGHT", "315"))
JPEG_QUALITY = int(os.getenv("JPEG_QUALITY", "85"))
MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))
ALLOW_PRIVATE_IPS = os.getenv("ALLOW_PRIVATE_IPS", "false").lower() == "true"

s3 = boto3.client("s3", region_name=AWS_REGION)


def is_valid_url(url: str) -> bool:
    if not url or len(url) > MAX_URL_LENGTH:
        return False
    try:
        parsed = urlparse(url.strip())
        return parsed.scheme in ("http", "https") and bool(parsed.netloc)
    except Exception:
        return False


def normalize_url(url: str) -> str:
    url = url.strip()
    if not re.match(r"^https?://", url, re.IGNORECASE):
        url = "https://" + url
    return url


def is_private_hostname(hostname: str) -> bool:
    import socket
    import ipaddress

    try:
        infos = socket.getaddrinfo(hostname, None)
        for info in infos:
            ip = info[4][0]
            addr = ipaddress.ip_address(ip)
            if (
                addr.is_private
                or addr.is_loopback
                or addr.is_link_local
                or addr.is_reserved
                or addr.is_multicast
            ):
                return True
        return False
    except Exception:
        return True


def safe_url(url: str) -> Tuple[bool, Optional[str]]:
    url = normalize_url(url)
    if not is_valid_url(url):
        return False, "Invalid URL"
    parsed = urlparse(url)
    if not ALLOW_PRIVATE_IPS and is_private_hostname(parsed.hostname or ""):
        return False, "Private or non-routable hosts are not allowed"
    return True, url


def make_key(url: str) -> str:
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX.rstrip('/')}/{digest[:2]}/{digest}.jpg"


def get_s3_url(key: str) -> str:
    if PUBLIC_BASE_URL:
        return f"{PUBLIC_BASE_URL.rstrip('/')}/{key}"
    return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"


def object_exists(bucket: str, key: str) -> bool:
    try:
        s3.head_object(Bucket=bucket, Key=key)
        return True
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code", "")
        if code in ("404", "NoSuchKey", "NotFound"):
            return False
        raise


def create_driver() -> webdriver.Chrome:
    options = Options()
    options.binary_location = CHROME_BINARY
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--window-size=%d,%d" % (VIEWPORT_WIDTH, VIEWPORT_HEIGHT))
    options.add_argument("--disable-blink-features=AutomationControlled")
    options.add_argument("--disable-background-networking")
    options.add_argument("--disable-background-timer-throttling")
    options.add_argument("--disable-client-side-phishing-detection")
    options.add_argument("--disable-default-apps")
    options.add_argument("--disable-extensions")
    options.add_argument("--disable-hang-monitor")
    options.add_argument("--disable-popup-blocking")
    options.add_argument("--disable-prompt-on-repost")
    options.add_argument("--disable-sync")
    options.add_argument("--metrics-recording-only")
    options.add_argument("--mute-audio")
    options.add_argument("--no-first-run")
    options.add_argument("--safebrowsing-disable-auto-update")
    options.add_argument("--ignore-certificate-errors")
    options.page_load_strategy = "eager"

    service = webdriver.ChromeService(executable_path=CHROMEDRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=options)
    driver.set_page_load_timeout(PAGELOAD_TIMEOUT)
    return driver


def capture_screenshot(url: str) -> bytes:
    driver = None
    png_path = None
    try:
        driver = create_driver()
        driver.get(url)
        time.sleep(RENDER_WAIT_SECONDS)

        with tempfile.NamedTemporaryFile(suffix=".png", delete=False) as tmp:
            png_path = tmp.name

        success = driver.save_screenshot(png_path)
        if not success:
            raise RuntimeError("Failed to save screenshot")

        with Image.open(png_path) as img:
            img = img.convert("RGB")
            img.thumbnail((THUMB_WIDTH, THUMB_HEIGHT))
            canvas = Image.new("RGB", (THUMB_WIDTH, THUMB_HEIGHT), (255, 255, 255))
            offset_x = max((THUMB_WIDTH - img.width) // 2, 0)
            offset_y = max((THUMB_HEIGHT - img.height) // 2, 0)
            canvas.paste(img, (offset_x, offset_y))

            out = io.BytesIO()
            canvas.save(out, format="JPEG", quality=JPEG_QUALITY, optimize=True)
            return out.getvalue()
    except (WebDriverException, TimeoutException) as e:
        logger.exception("Browser error while capturing screenshot")
        raise RuntimeError(f"Browser error: {str(e)}")
    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass
        if png_path and os.path.exists(png_path):
            try:
                os.remove(png_path)
            except Exception:
                pass


def upload_to_s3(image_bytes: bytes, key: str, source_url: str) -> str:
    metadata = {
        "source_url_sha256": hashlib.sha256(source_url.encode("utf-8")).hexdigest(),
        "generated_at": str(int(time.time())),
    }
    s3.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=image_bytes,
        ContentType="image/jpeg",
        ACL="public-read",
        CacheControl="public, max-age=31536000, immutable",
        Metadata=metadata,
    )
    return get_s3_url(key)


@app.get("/health")
def health():
    return jsonify({"ok": True})


@app.post("/screenshot")
def screenshot():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    payload = request.get_json(silent=True) or {}
    input_url = payload.get("url") or request.args.get("url", "")
    force = str(payload.get("force", request.args.get("force", "false"))).lower() == "true"

    ok, result = safe_url(input_url)
    if not ok:
        return jsonify({"error": result}), 400

    url = result
    key = make_key(url)

    try:
        if not force and object_exists(S3_BUCKET, key):
            return jsonify(
                {
                    "url": url,
                    "thumbnail_url": get_s3_url(key),
                    "s3_key": key,
                    "cached": True,
                }
            )

        image_bytes = capture_screenshot(url)
        public_url = upload_to_s3(image_bytes, key, url)

        return jsonify(
            {
                "url": url,
                "thumbnail_url": public_url,
                "s3_key": key,
                "cached": False,
                "size_bytes": len(image_bytes),
            }
        )
    except Exception as e:
        logger.exception("Failed to generate screenshot")
        return jsonify({"error": str(e)}), 500


@app.post("/invalidate")
def invalidate():
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET is not configured"}), 500

    payload = request.get_json(silent=True) or {}
    input_url = payload.get("url") or request.args.get("url", "")
    ok, result = safe_url(input_url)
    if not ok:
        return jsonify({"error": result}), 400

    key = make_key(result)
    try:
        s3.delete_object(Bucket=S3_BUCKET, Key=key)
        return jsonify({"deleted": True, "s3_key": key})
    except Exception as e:
        logger.exception("Failed to delete screenshot")
        return jsonify({"error": str(e)}), 500


